+    pub fn deserialize<'de, D: Deserializer<'de>>(
+        deserializer: D,
+    ) -> Result<BTreeMap<PropertyKey, PropertyDescriptor>, D::Error> {
+        let pairs: Vec<(PropertyKey, PropertyDescriptor)> = Vec::deserialize(deserializer)?;
+        Ok(pairs.into_iter().collect())
+    }
